import fp from 'fastify-plugin';
import fastifyAuth from '@fastify/auth';
import fastifyJWT from '@fastify/jwt';
import type { FastifyPluginAsync, FastifyRequest, FastifyReply } from 'fastify';

// JWT payload type
export interface JWTPayload {
  id: string;
  email: string;
  role: string;
}

// Extend JWT namespace
declare module '@fastify/jwt' {
  interface FastifyJWT {
    payload: JWTPayload;
    user: JWTPayload;
  }
}

const authPlugin: FastifyPluginAsync = async (fastify) => {
  // Register JWT plugin
  await fastify.register(fastifyJWT, {
    secret: fastify.config.JWT_SECRET,
    sign: {
      expiresIn: fastify.config.JWT_EXPIRES_IN,
    },
  });

  // Register auth plugin
  await fastify.register(fastifyAuth);

  // Authentication decorator
  fastify.decorate('authenticate', async function (request: FastifyRequest, reply: FastifyReply) {
    try {
      await request.jwtVerify();
    } catch (err) {
      return reply.status(401).send({
        success: false,
        error: {
          message: 'Unauthorized',
          statusCode: 401,
        },
      });
    }
  });

  // Authorization decorator (example for role-based auth)
  fastify.decorate('authorize', (roles: string[]) => {
    return async function (request: FastifyRequest, reply: FastifyReply) {
      if (!request.user) {
        return reply.status(401).send({
          success: false,
          error: {
            message: 'Unauthorized',
            statusCode: 401,
          },
        });
      }

      if (!roles.includes(request.user.role)) {
        return reply.status(403).send({
          success: false,
          error: {
            message: 'Forbidden',
            statusCode: 403,
          },
        });
      }
    };
  });
};

// Extend Fastify instance type
declare module 'fastify' {
  interface FastifyInstance {
    authenticate: (request: FastifyRequest, reply: FastifyReply) => Promise<void>;
    authorize: (roles: string[]) => (request: FastifyRequest, reply: FastifyReply) => Promise<void>;
  }
}

export default fp(authPlugin, {
  name: 'auth',
  dependencies: ['env'],
});

import type { FastifyInstance, FastifyReply, FastifyRequest } from "fastify";
import { type Static, Type } from "typebox";
import { UserSchema } from "@/api-lib/types/user.type.js";
import { UserProviderSchema } from "@/api-lib/types/user-provider.type.js";
import { UserProviderType } from "@/db/types/user-providers.db-types.js";
import { TypeRef } from "@/types.js";

const CreateEMailUserRequestSchema = Type.Object(
  {
    givenName: Type.String({
      minLength: 1,
      maxLength: 50,
    }),
    familyName: Type.String({
      minLength: 1,
      maxLength: 100,
    }),
    email: Type.String({
      minLength: 3,
      maxLength: 255,
      format: "email",
    }),
    password: Type.String({
      minLength: 8,
      maxLength: 64,
    }),
  },
  { $id: "CreateEMailUserRequest" },
);

export type CreateEMailUserRequest = Static<typeof CreateEMailUserRequestSchema>;

const CreateEMailUserResponseSchema = Type.Object(
  {
    user: TypeRef(UserSchema),
    provider: TypeRef(UserProviderSchema),
  },
  { $id: "CreateEMailUserResponse" },
);

export type CreateEMailUserResponse = Static<typeof CreateEMailUserResponseSchema>;

export async function createEMailUserRoute(fastify: FastifyInstance) {
  fastify.addSchema(CreateEMailUserRequestSchema);
  fastify.addSchema(CreateEMailUserResponseSchema);

  fastify.post(
    "/email",
    {
      schema: {
        operationId: "createEMailUser",
        tags: ["user"],
        description: "Create an e-mail-based account",
        body: Type.Ref("CreateEMailUserRequest"),
        response: {
          "200": Type.Ref("CreateEMailUserResponse"),
        },
      },
    },
    createEMailUserController,
  );
}

export async function createEMailUserController(
  request: FastifyRequest<{
    Body: CreateEMailUserRequest;
  }>,
  reply: FastifyReply,
) {
  const { familyName, givenName, password, email } = request.body;

  request.log.info(`Creating e-mail user: ${email}`);

  const user = await request.ctx.services.users.createEMailUser({
    user: {
      givenName,
      familyName,
    },
    email,
    password,
  });

  const response: CreateEMailUserResponse = {
    user: {
      id: user.id,
      givenName: user.givenName,
      familyName: user.familyName,
    },
    provider: {
      userId: user.id,
      providerType: UserProviderType.EMail,
      accountId: email,
    },
  };

  reply.send(response);
}

'use strict'

const fp = require('fastify-plugin')
const { MongoClient, ObjectId } = require('mongodb')

function decorateFastifyInstance (fastify, client, options) {
  const { forceClose, database, name, newClient } = options

  if (newClient) {
    // done() is not needed because .close() returns a Promise
    fastify.addHook('onClose', function closeMongoDb () {
      return client.close(forceClose)
    })
  }

  const mongo = {
    client,
    ObjectId
  }
  if (name) {
    if (!fastify.mongo) {
      fastify.decorate('mongo', mongo)
    }
    if (fastify.mongo[name]) {
      throw Error('Connection name already registered: ' + name)
    }

    fastify.mongo[name] = mongo
  } else {
    if (fastify.mongo) {
      throw Error('fastify-mongodb has already registered')
    }
  }

  if (database) {
    mongo.db = client.db(database)
  }

  if (!fastify.mongo) {
    fastify.decorate('mongo', mongo)
  }
}

async function fastifyMongodb (fastify, options) {
  options = Object.assign({
    serverSelectionTimeoutMS: 7500
  }, options)
  const { forceClose, name, database, url, client, ...opts } = options

  if (client) {
    decorateFastifyInstance(fastify, client, {
      newClient: false,
      forceClose,
      database,
      name
    })
  } else {
    if (!url) {
      throw Error('`url` parameter is mandatory if no client is provided')
    }

    const urlTokens = /\w\/([^?]*)/g.exec(url)
    const parsedDbName = urlTokens && urlTokens[1]
    const databaseName = database || parsedDbName

    const client = new MongoClient(url, opts)
    await client.connect()

    decorateFastifyInstance(fastify, client, {
      newClient: true,
      forceClose,
      database: databaseName,
      name
    })
  }
}

module.exports = fp(fastifyMongodb, {
  fastify: '5.x',
  name: '@fastify/mongodb'
})
module.exports.default = fastifyMongodb
module.exports.fastifyMongodb = fastifyMongodb

module.exports.mongodb = require('mongodb')

module.exports.ObjectId = ObjectId

'use strict'

const RedisStore = require('connect-redis').default
const Fastify = require('fastify')
const Redis = require('ioredis')
const fileStoreFactory = require('session-file-store')
const { isMainThread } = require('node:worker_threads')

const fastifySession = require('..')
const fastifyCookie = require('@fastify/cookie')

let redisClient

function createServer (sessionPlugin, cookiePlugin, storeType) {
  let requestCounter = 0
  let store

  if (storeType === 'redis') {
    if (!redisClient) {
      redisClient = new Redis()
    }
    store = new RedisStore({ client: redisClient })
  } else if (storeType === 'file') {
    const FileStore = fileStoreFactory(sessionPlugin)
    store = new FileStore({})
  }

  const fastify = Fastify()

  fastify.register(cookiePlugin)
  fastify.register(sessionPlugin, {
    secret: 'cNaoPYAwF60HZJzkcNaoPYAwF60HZJzk',
    saveUninitialized: false,
    cookie: { secure: false },
    store
  })

  fastify.get('/', (request, reply) => {
    // modify session every 10 requests
    if (requestCounter % 10 === 0) {
      request.session.userId = requestCounter
    } else {
      request.session.userId = 0
    }

    requestCounter++

    reply.send(200)
  })

  return fastify
}

function testFunction (sessionPlugin, cookiePlugin, storeType) {
  const server = createServer(sessionPlugin, cookiePlugin, storeType)

  return async function () {
    const { headers } = await server.inject('/')
    const setCookieHeader = headers['set-cookie']

    if (!setCookieHeader) {
      throw new Error('Missing set-cookie header')
    }

    const { sessionId } = server.parseCookie(setCookieHeader)

    // make 25 "requests" with the new session
    await Promise.all(
      new Array(1).fill(0).map(() => server.inject({ path: '/', headers: { cookie: `sessionId=${sessionId}` } }))
    )
  }
}

async function main () {
  const { default: cronometro } = await import('cronometro')

  return cronometro(
    {
      memory: testFunction(fastifySession, fastifyCookie),
      file: testFunction(fastifySession, fastifyCookie, 'file'),
      redis: {
        test: testFunction(fastifySession, fastifyCookie, 'redis'),
        async after () {
          return redisClient.disconnect()
        }
      }
    },
    {
      iterations: 25,
      print: { compare: true }
    }
  )
}

if (isMainThread) {
  main()
    .then(() => redisClient.quit())
    .catch(error => console.error(error))
} else {
  module.exports = main
}

import { FastifyReply, FastifyRequest } from 'fastify';
import { prisma } from '../utils';
import { ERRORS, handleServerError } from '../helpers/errors.helper';
import * as JWT from 'jsonwebtoken';
import { utils } from '../utils';
import { STANDARD } from '../constants/request';
import { IUserLoginDto, IUserSignupDto } from '../schemas/User';

export const login = async (
  request: FastifyRequest<{
    Body: IUserLoginDto;
  }>,
  reply: FastifyReply,
) => {
  try {
    const { email, password } = request.body;
    const user = await prisma.user.findUnique({ where: { email } });
    if (!user) {
      return reply
        .code(ERRORS.userNotExists.statusCode)
        .send(ERRORS.userNotExists.message);
    }

    const checkPass = await utils.compareHash(password, user.password);
    if (!checkPass) {
      return reply
        .code(ERRORS.userCredError.statusCode)
        .send(ERRORS.userCredError.message);
    }

    const token = JWT.sign(
      {
        id: user.id,
        email: user.email,
      },
      process.env.APP_JWT_SECRET as string,
    );

    return reply.code(STANDARD.OK.statusCode).send({
      token,
      user,
    });
  } catch (err) {
    return handleServerError(reply, err);
  }
};

export const signUp = async (
  request: FastifyRequest<{
    Body: IUserSignupDto;
  }>,
  reply: FastifyReply,
) => {
  try {
    const { email, password, firstName, lastName } = request.body;
    const user = await prisma.user.findUnique({ where: { email } });
    if (user) {
      return reply.code(ERRORS.userExists.statusCode).send(ERRORS.userExists);
    }

    const hashPass = await utils.genSalt(10, password);
    const createUser = await prisma.user.create({
      data: {
        email,
        first_name: firstName.trim(),
        last_name: lastName.trim(),
        password: String(hashPass),
      },
    });

    const token = JWT.sign(
      {
        id: createUser.id,
        email: createUser.email,
      },
      process.env.APP_JWT_SECRET as string,
    );

    delete createUser.password;

    return reply.code(STANDARD.OK.statusCode).send({
      token,
      user: createUser,
    });
  } catch (err) {
    return handleServerError(reply, err);
  }
};

'use strict'

const Fastify = require('fastify')
const mq = require('mqemitter')
const mercurius = require('..')

async function start () {
  const app = Fastify()

  const schema = `
    type Notification {
      id: ID!
      message: String
    }

    type Mutation {
      addNotification(message: String): Notification
    }

    type Subscription {
      notificationAdded: Notification
    }
  `

  const emitter = mq()

  const resolvers = {
    Mutation: {
      addNotification: async (_, { message }) => {
        const notification = {
          id: 1,
          message
        }
        await emitter.emit({
          topic: 'NOTIFICATION_ADDED',
          payload: {
            notificationAdded: notification
          }
        })

        return notification
      }
    },
    Subscription: {
      notificationAdded: {
        subscribe: (root, args, { pubsub }) => pubsub.subscribe('NOTIFICATION_ADDED')
      }
    }
  }

  app.register(mercurius, {
    schema,
    resolvers,
    subscription: {
      emitter
    }
  })

  await app.ready()

  app.graphql.addHook('preSubscriptionParsing', async function (schema, source, context, id) {
    console.log('preSubscriptionParsing called')
  })

  app.graphql.addHook('preSubscriptionExecution', async function (schema, document, context, id) {
    console.log('preSubscriptionExecution called')
  })

  app.graphql.addHook('onSubscriptionResolution', async function (execution, context, id) {
    console.log('onSubscriptionResolution called')
  })

  app.graphql.addHook('onSubscriptionEnd', async function (context, id) {
    console.log('onSubscriptionEnd called')
  })

  app.graphql.addHook('onSubscriptionConnectionClose', async function (context, code, reason) {
    console.log('onSubscriptionConnectionClose called')
  })

  app.graphql.addHook('onSubscriptionConnectionError', async function (context, error) {
    console.log('onSubscriptionConnectionError called')
  })

  await app.listen({ port: 3000 })
}

