import viteFastify from '@fastify/vite/plugin'
import {
  prefix,
  resolveId,
  loadSource,
  loadVirtualModule,
  createPlaceholderExports,
} from './virtual.js'
import { closeBundle } from './preload.js'

export default function viteFastifyReactPlugin({ ts } = {}) {
  const context = {
    root: null,
  }
  return [
    viteFastify({
      clientModule: ts ? '$app/index.ts' : '$app/index.js',
    }),
    {
      // https://vite.dev/guide/api-plugin#conventions
      name: 'vite-plugin-react-fastify',
      config,
      configResolved: configResolved.bind(context),
      resolveId: resolveId.bind(context),
      async load(id) {
        if (id.includes('?server') && !this.environment.config.build?.ssr) {
          const source = loadSource(id)
          return createPlaceholderExports(source)
        }
        if (id.includes('?client') && this.environment.config.build?.ssr) {
          const source = loadSource(id)
          return createPlaceholderExports(source)
        }
        if (prefix.test(id)) {
          const [, virtual] = id.split(prefix)
          if (virtual) {
            return loadVirtualModule(virtual)
          }
        }
      },
      transformIndexHtml: {
        order: 'post',
        handler: transformIndexHtml.bind(context),
      },
      closeBundle() {
        closeBundle.call(this, context.resolvedBundle)
      },
    },
  ]
}

function transformIndexHtml(html, { bundle }) {
  if (!bundle) {
    return
  }
  this.indexHtml = html
  this.resolvedBundle = bundle
}

function configResolved(config) {
  this.resolvedConfig = config
  this.root = config.root
}

function config(config, { command }) {
  if (command === 'build') {
    if (!config.build) {
      config.build = {}
    }
    if (!config.build.rollupOptions) {
      config.build.rollupOptions = {}
    }
    config.build.rollupOptions.onwarn = onwarn
  }
}

function onwarn(warning, rollupWarn) {
  if (
    !(
      warning.code == 'MISSING_EXPORT' &&
      warning.message?.includes?.('"scrollBehavior" is not exported')
    ) &&
    !(
      warning.code == 'PLUGIN_WARNING' &&
      warning.message?.includes?.('dynamic import will not move module into another chunk')
    ) &&
    !(warning.code == 'UNUSED_EXTERNAL_IMPORT' && warning.exporter === 'vue')
  ) {
    rollupWarn(warning)
  }
}

import { Readable } from 'streamx'

import { kHeaders, kReq, kUrl } from './symbols.js'

const noop = () => {}

function onAbort() {
  this.emit('aborted')
}

export class Request extends Readable {
  constructor(req, socket, method) {
    super()

    this.socket = socket
    this.method = method
    this.httpVersion = '1.1'
    this.readableEnded = false
    this[kReq] = req
    this[kUrl] = null
    this[kHeaders] = null

    this.once('error', noop)
    const destroy = super.destroy.bind(this)
    socket.once('error', destroy)
    socket.once('close', destroy)
    socket.once('aborted', onAbort.bind(this))
  }

  get aborted() {
    return this.socket.aborted
  }

  get url() {
    let url = this[kUrl]
    if (url) return url
    const query = this[kReq].getQuery()
    url = this[kUrl] =
      this[kReq].getUrl() + (query && query.length > 0 ? `?${query}` : '')
    return url
  }

  set url(url) {
    this[kUrl] = url
  }

  get headers() {
    let headers = this[kHeaders]
    if (headers) return headers
    headers = this[kHeaders] = {}
    this[kReq].forEach((k, v) => {
      headers[k] = v
    })
    return headers
  }

  setEncoding(encoding) {
    this.socket.setEncoding(encoding)
  }

  setTimeout(timeout) {
    this.socket.setTimeout(timeout)
  }

  destroy(err) {
    if (this.destroyed || this.destroying) return
    this.socket.destroy(err)
  }

  _read(cb) {
    if (this.destroyed || this.destroying || this.socket.destroyed) return cb()

    this.socket.onRead((err, data) => {
      if (err) return cb(err)

      if (this.destroyed || this.destroying) return cb()

      this.push(data)

      if (!data) {
        this.readableEnded = true
        cb()
      }
    })
  }
}

const { readFileSync, existsSync } = require('node:fs')
const { resolve } = require('node:path')
const inject = require('@rollup/plugin-inject')

function viteFastifyHtmx() {
  const prefix = /^\/:/
  const virtualRoot = resolve(__dirname, 'virtual')
  const virtualModules = ['client.js', 'layouts/', 'layouts.js', 'routes.js', 'root.jsx']
  virtualModules.includes = function (virtual) {
    if (!virtual) {
      return false
    }
    for (const entry of this) {
      if (virtual.startsWith(entry)) {
        return true
      }
    }
    return false
  }

  let viteProjectRoot

  function loadVirtualModuleOverride(virtual) {
    if (!virtualModules.includes(virtual)) {
      return
    }
    const overridePath = resolve(viteProjectRoot, virtual)
    if (existsSync(overridePath)) {
      return overridePath
    }
  }

  function loadVirtualModule(virtual) {
    if (!virtualModules.includes(virtual)) {
      return
    }
    const code = readFileSync(resolve(virtualRoot, virtual), 'utf8')
    return {
      code,
      map: null,
    }
  }

  return [
    inject({
      htmx: 'htmx.org',
      Html: '@kitajs/html',
    }),
    {
      name: 'vite-plugin-fastify-htmx',
      config(config, { command }) {
        config.esbuild = {
          jsxFactory: 'Html.createElement',
          jsxFragment: 'Html.Fragment',
        }
        if (command === 'build' && config.build?.ssr) {
          config.build.rollupOptions = {
            output: {
              format: 'es',
            },
          }
        }
      },
      configResolved(config) {
        viteProjectRoot = config.root
      },
      async resolveId(id) {
        const [, virtual] = id.split(prefix)
        if (virtual) {
          const override = await loadVirtualModuleOverride(virtual)
          if (override) {
            return override
          }
          return id
        }
      },
      load(id, options) {
        if (options?.ssr && (id.endsWith('.client.js') || id.endsWith('.client.ts'))) {
          return {
            code: '',
            map: null,
          }
        }
        const [, virtual] = id.split(prefix)
        return loadVirtualModule(virtual)
      },
    },
  ]
}

module.exports = viteFastifyHtmx

import { FastifyRequest } from 'fastify'
import { File, FilesObject } from '../interfaces'

export type Strategy = 'NONE' | 'VALUE' | 'ARRAY' | 'OBJECT'
type Placeholder = {
  fieldname?: string
}

function arrayRemove(arr: any[], item: Placeholder) {
  const idx = arr.indexOf(item)
  if (~idx) {
    arr.splice(idx, 1)
  }
}

class FileAppender {
  strategy: Strategy
  request: FastifyRequest

  constructor(strategy: Strategy, request: FastifyRequest) {
    this.strategy = strategy
    this.request = request

    switch (strategy) {
      case 'NONE':
        break
      case 'VALUE':
        break
      case 'ARRAY':
        request.files = []
        break
      case 'OBJECT':
        request.files = Object.create(null)
        break
      default:
        throw new Error('Unknown file strategy: ' + strategy)
    }
  }
  insertPlaceholder(file: Pick<File, 'fieldname' | 'originalname' | 'encoding' | 'mimetype'>) {
    const placeholder = {
      fieldname: file.fieldname,
    }

    switch (this.strategy) {
      case 'NONE':
        break
      case 'VALUE':
        break
      case 'ARRAY':
        ;(this.request.files as Partial<File>[]).push(placeholder)
        break
      case 'OBJECT':
        if ((this.request.files as FilesObject)[file.fieldname]) {
          ;(this.request.files as FilesObject)[file.fieldname].push(placeholder)
        } else {
          ;(this.request.files as FilesObject)[file.fieldname] = [placeholder]
        }
        break
    }

    return placeholder
  }
  removePlaceholder(placeholder: Placeholder) {
    switch (this.strategy) {
      case 'NONE':
        break
      case 'VALUE':
        break
      case 'ARRAY':
        arrayRemove(this.request.files as Partial<File>[], placeholder)
        break
      case 'OBJECT':
        if (placeholder.fieldname) {
          if ((this.request.files as FilesObject)[placeholder.fieldname].length === 1) {
            delete (this.request.files as FilesObject)[placeholder.fieldname]
          } else {
            arrayRemove((this.request.files as FilesObject)[placeholder.fieldname], placeholder)
          }
        }
        break
    }
  }
  replacePlaceholder(placeholder: Placeholder, file: File) {
    if (this.strategy === 'VALUE') {
      this.request.file = file
      return
    }

    delete placeholder.fieldname
    Object.assign(placeholder, file)
  }
}

export default FileAppender
